#include <iostream>
#include <string>
using namespace std;

class BankAccount {
private:
    string accountNumber;
    string ownerName;
    double balance;

public:
    // Constructor
    BankAccount(string accNum, string name, double initialBalance) {
        this->accountNumber = accNum;
        this->ownerName = name;
        // Validation in setter
        setBalance(initialBalance);
    }

    // Getters
    string getAccountNumber() {
        return accountNumber;
    }

    string getOwnerName() {
        return ownerName;
    }

    double getBalance() {
        return balance;
    }

    // Setters with validation
    void setOwnerName(string name) {
        if (!name.empty()) {
            this->ownerName = name;
        } else {
            cout << "Error: Name cannot be empty!" << endl;
        }
    }

    void setBalance(double amount) {
        if (amount >= 0) {
            this->balance = amount;
        } else {
            cout << "Error: Balance cannot be negative!" << endl;
            this->balance = 0;
        }
    }

    // Business methods
    void deposit(double amount) {
        if (amount > 0) {
            balance += amount;
            cout << "Deposited: $" << amount << endl;
        } else {
            cout << "Error: Deposit amount must be positive!" << endl;
        }
    }

    bool withdraw(double amount) {
        if (amount > 0 && amount <= balance) {
            balance -= amount;
            cout << "Withdrawn: $" << amount << endl;
            return true;
        }
        cout << "Error: Invalid withdrawal amount!" << endl;
        return false;
    }

    void displayInfo() {
        cout << "Account: " << accountNumber << endl;
        cout << "Owner: " << ownerName << endl;
        cout << "Balance: $" << balance << endl;
    }
};

int main() {
    BankAccount account("ACC001", "John Doe", 1000.0);

    account.displayInfo();
    cout << "---" << endl;

    account.deposit(500);
    account.withdraw(200);

    cout << "---" << endl;
    cout << "Current Balance: $" << account.getBalance() << endl;

    // This won't work - balance is private
    // account.balance = 1000000; // Error!

    return 0;
}

