// C++ - Advanced Class Concepts
#include <iostream>
#include <string>
#include <vector>
using namespace std;

// Static Members Example
class Employee {
private:
    int id;
    string name;
    static int employeeCount;  // Static variable
    static int nextId;         // Auto-increment ID

public:
    Employee(string name) {
        this->id = ++nextId;
        this->name = name;
        employeeCount++;
        cout << "Employee created: " << name << " (ID: " << id << ")" << endl;
    }

    ~Employee() {
        employeeCount--;
        cout << "Employee destroyed: " << name << endl;
    }

    // Static method
    static int getEmployeeCount() {
        return employeeCount;
    }

    static int getNextId() {
        return nextId + 1;
    }

    void display() {
        cout << "ID: " << id << ", Name: " << name << endl;
    }

    int getId() { return id; }
    string getName() { return name; }
};

// Initialize static members (required in C++)
int Employee::employeeCount = 0;
int Employee::nextId = 0;

// Composition Example - Strong Ownership
class Engine {
private:
    int horsepower;
    string type;

public:
    Engine(int hp, string type) : horsepower(hp), type(type) {
        cout << "Engine created: " << type << endl;
    }

    ~Engine() {
        cout << "Engine destroyed: " << type << endl;
    }

    void start() {
        cout << "Engine (" << horsepower << "hp " << type << ") starting..." << endl;
    }

    string getInfo() {
        return to_string(horsepower) + "hp " + type;
    }
};

class Car {
private:
    string brand;
    Engine* engine;  // Composition: Car OWNS the Engine

public:
    Car(string brand, int hp, string engineType) {
        this->brand = brand;
        this->engine = new Engine(hp, engineType);  // Car creates Engine
        cout << "Car created: " << brand << endl;
    }

    ~Car() {
        delete engine;  // Car destroys Engine (ownership)
        cout << "Car destroyed: " << brand << endl;
    }

    void start() {
        cout << brand << " starting..." << endl;
        engine->start();
    }

    void displayInfo() {
        cout << "Brand: " << brand << endl;
        cout << "Engine: " << engine->getInfo() << endl;
    }
};

// Aggregation Example - Weak Ownership
class Department {
private:
    string name;
    vector<Employee*> employees;  // Aggregation: Dept has Employees but doesn't own them

public:
    Department(string name) : name(name) {
        cout << "Department created: " << name << endl;
    }

    ~Department() {
        // Don't delete employees - we don't own them!
        cout << "Department destroyed: " << name << endl;
    }

    void addEmployee(Employee* emp) {
        employees.push_back(emp);
        cout << "Added " << emp->getName() << " to " << name << endl;
    }

    void removeEmployee(Employee* emp) {
        for (auto it = employees.begin(); it != employees.end(); ++it) {
            if (*it == emp) {
                employees.erase(it);
                cout << "Removed " << emp->getName() << " from " << name << endl;
                return;
            }
        }
    }

    void listEmployees() {
        cout << "Department: " << name << endl;
        cout << "Employees:" << endl;
        for (Employee* emp : employees) {
            cout << "  - " << emp->getName() << endl;
        }
    }
};

int main() {
    cout << "=== Static Members Demo ===" << endl;
    cout << "Initial count: " << Employee::getEmployeeCount() << endl;

    Employee* e1 = new Employee("Alice");
    Employee* e2 = new Employee("Bob");

    cout << "Current count: " << Employee::getEmployeeCount() << endl;
    cout << "Next ID will be: " << Employee::getNextId() << endl;

    cout << "\n=== Composition Demo ===" << endl;
    {
        Car car("Tesla", 450, "Electric");
        car.displayInfo();
        car.start();
    }  // Car and Engine both destroyed here

    cout << "\n=== Aggregation Demo ===" << endl;
    Department* itDept = new Department("IT");
    itDept->addEmployee(e1);
    itDept->addEmployee(e2);
    itDept->listEmployees();

    delete itDept;  // Department destroyed, but employees still exist

    cout << "\nEmployees still exist:" << endl;
    e1->display();
    e2->display();

    // Cleanup
    delete e1;
    delete e2;

    cout << "\nFinal count: " << Employee::getEmployeeCount() << endl;

    return 0;
}

