private:
    static Logger* instance;
    static mutex mtx;
    static int logCount;

    // Private constructor
    Logger() {
        cout << "Logger instance created" << endl;
    }

    string getTimestamp() {
        time_t now = time(0);
        char* dt = ctime(&now);
        string timestamp(dt);
        timestamp.pop_back();  // Remove newline
        return timestamp;
    }

public:
