// Course class (for Association)
class Course {
private:
    string code;
    string name;
    int credits;

public:
    Course(string code, string name, int credits)
        : code(code), name(name), credits(credits) {
        cout << "  Course created: " << name << endl;
    }

    ~Course() {
        cout << "  Course destroyed: " << name << endl;
    }

    string getName() const { return name; }
    string getCode() const { return code; }

    void display() const {
        cout << "    " << code << ": " << name << " (" << credits << " credits)" << endl;
    }
};

// Professor class (Aggregation target, Association with Courses)
class Professor {
private:
    int id;
    string name;
    string specialization;
    vector<Course*> courses;  // Association: doesn't own courses

public:
    Professor(int id, string name, string spec)
        : id(id), name(name), specialization(spec) {
        cout << "  Professor created: " << name << endl;
    }

    ~Professor() {
        cout << "  Professor destroyed: " << name << endl;
    }

    void assignCourse(Course* course) {
        courses.push_back(course);
        cout << "    " << name << " assigned to teach " << course->getName() << endl;
    }

    void removeCourse(Course* course) {
        for (auto it = courses.begin(); it != courses.end(); ++it) {
            if (*it == course) {
                courses.erase(it);
                cout << "    " << name << " removed from " << course->getName() << endl;
                return;
            }
        }
    }

    string getName() const { return name; }
    int getId() const { return id; }

    void display() const {
        cout << "    Prof. " << name << " (" << specialization << ")" << endl;
        if (!courses.empty()) {
            cout << "      Teaching:" << endl;
            for (const Course* c : courses) {
                cout << "        - " << c->getName() << endl;
            }
        }
    }
};

