        : name(name), building(building) {
        cout << "  Department created: " << name << endl;
    }

    ~Department() {
        // Don't delete professors - we don't own them
        cout << "  Department destroyed: " << name << endl;
    }

    void addProfessor(Professor* prof) {
        professors.push_back(prof);
        cout << "    Added " << prof->getName() << " to " << name << endl;
    }

    void removeProfessor(Professor* prof) {
        for (auto it = professors.begin(); it != professors.end(); ++it) {
            if (*it == prof) {
                professors.erase(it);
                return;
            }
        }
    }

    string getName() const { return name; }

    void display() const {
        cout << "  Department: " << name << " (Building: " << building << ")" << endl;
        cout << "  Professors:" << endl;
        for (const Professor* p : professors) {
            p->display();
        }
